const amqp = require('amqplib');

const RabbitMQConfig = {
  url: 'amqp://localhost',
  queueName: 'example-queue'
};

async function consumeMessages() {
  try {
    const connection = await amqp.connect(RabbitMQConfig.url);
    const channel = await connection.createChannel();

    await channel.assertQueue(RabbitMQConfig.queueName, { durable: true });

    console.log('Consuming messages from queue:', RabbitMQConfig.queueName);

    await channel.consume(RabbitMQConfig.queueName, (msg) => {
      if (msg !== null) {
        const message = JSON.parse(msg.content.toString());
        handleMessage(message);
        channel.ack(msg);
      }
    });

  } catch (error) {
    console.error('Error consuming messages from queue:', error);
  }
}

